onClick:
{{
  insert_new_lead.run(() => {
    get_crm_main.run();
    closeModal('ModalNuevoLead');

    resetWidget('InputNombreLead');
    resetWidget('InputTelefonoLead');
    resetWidget('InputEmailLead');
    resetWidget('InputDistritosLead');
    resetWidget('InputDormitoriosLead');
    resetWidget('InputPresupuestoLead');
    resetWidget('SelectCanalLead');
    resetWidget('SelectPagoLead');
    resetWidget('SelectTiempoLead');

    showAlert('Lead creado correctamente', 'success');
  }, () => {
    showAlert('Error al crear lead', 'error');
  })
}}
